{
  "name": "CyberSoft - Lab Debt Tracker",
  "description": "A cybersecurity and cloud learning tracker featuring a 'Lab Debt' system with a soft cyber/pastel synthwave aesthetic. Track your daily labs, manage exam modes, and visualize your progress with a bento-style dashboard."
}

export type LabCategory = 'Cloud' | 'Network' | 'AppSec' | 'Mandarin' | 'Other';

export interface Lab {
  id: string;
  title: string;
  category: LabCategory;
  resourceLink: string;
  completedAt: string; // ISO string
}

export interface AppState {
  journeyStartDate: string; // ISO string
  labs: Lab[];
  isExamMode: boolean;
  examModeStartDate: string | null; // ISO string when toggled ON
  accumulatedExamDays: number; // Total days spent in exam mode previously
  weeklyGoal: number;
}

export const CATEGORIES: LabCategory[] = ['Cloud', 'Network', 'AppSec', 'Mandarin', 'Other'];

export const getDaysDiff = (start: Date, end: Date): number => {
  const diffTime = Math.abs(end.getTime() - start.getTime());
  return Math.floor(diffTime / (1000 * 60 * 60 * 24));
};

export const calculateDebt = (
  startDateStr: string,
  labsCompleted: number,
  isExamMode: boolean,
  examModeStartDateStr: string | null,
  accumulatedExamDays: number
): number => {
  const now = new Date();
  const startDate = new Date(startDateStr);

  // Total days elapsed since the very beginning
  const totalDaysPassed = getDaysDiff(startDate, now);

  // Calculate current session of exam mode if active
  let currentExamSessionDays = 0;
  if (isExamMode && examModeStartDateStr) {
    currentExamSessionDays = getDaysDiff(new Date(examModeStartDateStr), now);
  }

  const totalExamDays = accumulatedExamDays + currentExamSessionDays;

  // Effective learning days = Total days - days paused by Exam Mode
  const effectiveLearningDays = Math.max(0, totalDaysPassed - totalExamDays);

  // Debt = Target (1 lab per day) - Actual labs completed
  // Note: We +1 to include today as a day that "owes" a lab if it's already passed 24h or if we want to be strict.
  // Using calendar days is safer.
  return Math.max(0, effectiveLearningDays - labsCompleted);
};

export const getLabsThisWeek = (labs: { completedAt: string }[]): number => {
  const now = new Date();
  const startOfWeek = new Date(now);
  startOfWeek.setDate(now.getDate() - now.getDay()); // Sunday
  startOfWeek.setHours(0, 0, 0, 0);

  return labs.filter(lab => new Date(lab.completedAt) >= startOfWeek).length;
};

import React from 'react';

interface BentoCardProps {
  children: React.ReactNode;
  className?: string;
  title?: string;
  subtitle?: string;
}

export const BentoCard: React.FC<BentoCardProps> = ({ children, className = '', title, subtitle }) => {
