        <div className="mb-4">
          <h3 className="text-lg font-bold font-poppins text-gray-800">{title}</h3>
          {subtitle && <p className="text-sm text-gray-500">{subtitle}</p>}
        </div>
      )}
      {children}
    </div>
  );
};

import React from 'react';

