import React, { useState } from 'react';
import { LabCategory, CATEGORIES } from '../types';

interface LabEntryFormProps {
  onAddLab: (title: string, category: LabCategory, link: string) => void;
}

export const LabEntryForm: React.FC<LabEntryFormProps> = ({ onAddLab }) => {
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<LabCategory>('Cloud');
  const [link, setLink] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !link) return;
    onAddLab(title, category, link);
    setTitle('');
    setLink('');
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div>
        <label className="block text-sm font-medium text-gray-600 mb-1">Lab Title</label>
        <input
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="e.g., AWS VPC Peering Lab"
          className="w-full px-4 py-3 rounded-xl bg-white/60 border border-gray-100 focus:border-[#bfdbfe] focus:ring-2 focus:ring-[#bfdbfe] outline-none transition-all"
          required
        />
      </div>
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-gray-600 mb-1">Category</label>
          <select
            value={category}
            onChange={(e) => setCategory(e.target.value as LabCategory)}
            className="w-full px-4 py-3 rounded-xl bg-white/60 border border-gray-100 focus:border-[#bfdbfe] focus:ring-2 focus:ring-[#bfdbfe] outline-none transition-all appearance-none"
          >
            {CATEGORIES.map((cat) => (
              <option key={cat} value={cat}>
                {cat}
              </option>
            ))}
          </select>
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-600 mb-1">Resource Link</label>
          <input
            type="url"
            value={link}
            onChange={(e) => setLink(e.target.value)}
            placeholder="GitHub/Docs Link"
            className="w-full px-4 py-3 rounded-xl bg-white/60 border border-gray-100 focus:border-[#bfdbfe] focus:ring-2 focus:ring-[#bfdbfe] outline-none transition-all"
            required
          />
        </div>
      </div>
      <button
        type="submit"
        className="w-full py-3 bg-[#bfdbfe] hover:bg-[#a5c9f9] text-gray-800 font-bold rounded-xl transition-all shadow-sm hover:shadow-md active:scale-[0.98]"
      >
        Log Lab Activity 🌸
      </button>
    </form>
  );
};

import React from 'react';
import { Lab } from '../types';

interface WallOfProofProps {
  labs: Lab[];
  onDelete: (id: string) => void;
}

export const WallOfProof: React.FC<WallOfProofProps> = ({ labs, onDelete }) => {
  const sortedLabs = [...labs].sort((a, b) => new Date(b.completedAt).getTime() - new Date(a.completedAt).getTime());

  if (labs.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-12 text-gray-400">
        <p className="text-lg">No proof yet... Start your journey! 🚀</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 overflow-y-auto max-h-[500px] pr-2">
      {sortedLabs.map((lab) => (
        <div key={lab.id} className="group relative bg-white/80 border border-gray-100 p-4 rounded-2xl hover:shadow-md transition-all">
          <button
            onClick={() => onDelete(lab.id)}
            className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 p-1 text-gray-400 hover:text-red-400 transition-opacity"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="6 18L18 6M6 6l12 12" />
            </svg>
          </button>
          <div className="flex justify-between items-start mb-2">
            <span className="px-2 py-1 bg-[#fbcfe8] text-[10px] font-bold text-gray-700 rounded-md uppercase tracking-wider">
              {lab.category}
            </span>
            <span className="text-[10px] text-gray-400 font-mono">
              {new Date(lab.completedAt).toLocaleDateString()}
            </span>
          </div>
          <h4 className="font-semibold text-gray-800 mb-2 truncate pr-4">{lab.title}</h4>
          <a
            href={lab.resourceLink}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center text-xs font-medium text-blue-400 hover:text-blue-600 transition-colors"
          >
            View Resource
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 ml-1" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
            </svg>
          </a>
        </div>
      ))}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { AppState, Lab, LabCategory } from './types';
import { calculateDebt, getLabsThisWeek, getDaysDiff } from './utils/dateUtils';
import { BentoCard } from './components/BentoCard';
import { ExamToggle } from './components/ExamToggle';
import { LabEntryForm } from './components/LabEntryForm';
import { WallOfProof } from './components/WallOfProof';

const STORAGE_KEY = 'cybersoft_tracker_v1';

const INITIAL_STATE: AppState = {
  journeyStartDate: new Date().toISOString(),
  labs: [],
  isExamMode: false,
  examModeStartDate: null,
  accumulatedExamDays: 0,
  weeklyGoal: 7,
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Failed to parse storage", e);
      }
    }
    return INITIAL_STATE;
  });

  const [isEditingStart, setIsEditingStart] = useState(false);
  const [tempStartDate, setTempStartDate] = useState(state.journeyStartDate.split('T')[0]);

  // Sync with localStorage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const handleToggleExamMode = () => {
    setState(prev => {
      const now = new Date();
      if (!prev.isExamMode) {
        // Turning ON
        return {
          ...prev,
          isExamMode: true,
          examModeStartDate: now.toISOString(),
        };
      } else {
        // Turning OFF
        const sessionDays = prev.examModeStartDate 
          ? getDaysDiff(new Date(prev.examModeStartDate), now) 
          : 0;
        return {
          ...prev,
          isExamMode: false,
          examModeStartDate: null,
          accumulatedExamDays: prev.accumulatedExamDays + sessionDays,
        };
      }
    });
  };

  const handleAddLab = (title: string, category: LabCategory, link: string) => {
    const newLab: Lab = {
      id: crypto.randomUUID(),
      title,
      category,
      resourceLink: link,
      completedAt: new Date().toISOString(),
    };
    setState(prev => ({
      ...prev,
      labs: [...prev.labs, newLab],
    }));
  };

  const handleDeleteLab = (id: string) => {
    setState(prev => ({
      ...prev,
      labs: prev.labs.filter(l => l.id !== id),
    }));
  };

  const handleUpdateStartDate = () => {
    setState(prev => ({
      ...prev,
      journeyStartDate: new Date(tempStartDate).toISOString(),
    }));
    setIsEditingStart(false);
  };

  const debt = calculateDebt(
    state.journeyStartDate,
    state.labs.length,
    state.isExamMode,
    state.examModeStartDate,
    state.accumulatedExamDays
  );

  const weeklyProgress = getLabsThisWeek(state.labs);
  const progressPercent = Math.min(100, (weeklyProgress / state.weeklyGoal) * 100);

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-7xl mx-auto">
      {/* Header Section */}
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-bold font-poppins text-gray-800 flex items-center gap-2">
            CyberSoft <span className="text-[#fbcfe8]">🌸</span>
          </h1>
          <p className="text-gray-500 font-medium">Cloud & Security Learning OS</p>
        </div>

        <div className="flex flex-col items-end">
          <div className="text-xs font-mono text-gray-400 uppercase tracking-widest mb-1">Journey Started</div>
          {isEditingStart ? (
            <div className="flex gap-2">
              <input 
                type="date" 
                value={tempStartDate} 
                onChange={(e) => setTempStartDate(e.target.value)}
                className="bg-white/50 border border-gray-200 rounded-lg px-2 py-1 text-sm outline-none"
              />
              <button onClick={handleUpdateStartDate} className="bg-[#bfdbfe] px-3 py-1 rounded-lg text-xs font-bold text-gray-700">Set</button>
            </div>
          ) : (
            <button 
              onClick={() => setIsEditingStart(true)}
              className="text-lg font-semibold text-gray-700 hover:text-blue-400 transition-colors"
            >
              {new Date(state.journeyStartDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
            </button>
          )}
        </div>
      </header>

      {/* Main Bento Grid */}
      <main className="grid grid-cols-1 md:grid-cols-12 gap-6">

        {/* Dashboard Column */}
        <div className="md:col-span-4 space-y-6">
          {/* Status Card */}
          <BentoCard className="h-64 flex flex-col items-center justify-center relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-[#fbcfe8]/20 rounded-full -mr-16 -mt-16 blur-2xl group-hover:bg-[#fbcfe8]/30 transition-all duration-700"></div>
            <div className="absolute bottom-0 left-0 w-32 h-32 bg-[#bfdbfe]/20 rounded-full -ml-16 -mb-16 blur-2xl group-hover:bg-[#bfdbfe]/30 transition-all duration-700"></div>

            <div className="relative text-center">
              <h2 className="text-gray-400 font-mono text-xs uppercase tracking-[0.2em] mb-4">Current Status</h2>
              {debt === 0 ? (
                <div className="animate-bounce">
                  <span className="text-5xl mb-2 block">✨</span>
                  <span className="text-2xl font-bold font-poppins text-gray-800">You're a Legend!</span>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                  <span className="text-gray-800 font-mono text-7xl font-bold mb-2 tracking-tighter">
                    {debt}
                  </span>
                  <div className="flex items-center gap-2 text-[#fbcfe8] font-bold text-xl font-poppins">
                    Lab Debt 🌸
                  </div>
                </div>
              )}
            </div>
          </BentoCard>

          {/* Exam Mode Toggle */}
          <ExamToggle isEnabled={state.isExamMode} onToggle={handleToggleExamMode} />

          {/* Weekly Progress */}
          <BentoCard title="Weekly Progress" subtitle={`Goal: ${state.weeklyGoal} Labs`}>
            <div className="mt-4">
              <div className="flex justify-between items-end mb-2">
                <span className="text-3xl font-bold font-mono text-gray-800">{weeklyProgress}</span>
                <span className="text-gray-400 text-sm font-medium mb-1">{progressPercent.toFixed(0)}%</span>
              </div>
              <div className="w-full bg-white/50 rounded-full h-4 overflow-hidden border border-gray-100 p-[2px]">
                <div 
                  className="h-full bg-[#bfdbfe] rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(191,219,254,0.5)]"
                  style={{ width: `${progressPercent}%` }}
                />
              </div>
              <p className="mt-3 text-xs text-gray-500 text-center">
                {state.weeklyGoal - weeklyProgress > 0 
                  ? `${state.weeklyGoal - weeklyProgress} more to hit your goal!`
                  : "Weekly goal crushed! Keep it up! 🏆"}
              </p>
            </div>
          </BentoCard>
        </div>

        {/* Content Column */}
        <div className="md:col-span-8 space-y-6">
          {/* Lab Entry */}
          <BentoCard title="Log New Activity" subtitle="Record your learning proof">
            <LabEntryForm onAddLab={handleAddLab} />
          </BentoCard>

          {/* Wall of Proof */}
          <BentoCard title="Wall of Proof" subtitle="Your journey's evidence" className="flex-1">
            <WallOfProof labs={state.labs} onDelete={handleDeleteLab} />
          </BentoCard>
        </div>
      </main>

      {/* Footer */}
      <footer className="mt-12 text-center text-gray-400 text-xs font-mono uppercase tracking-widest border-t border-gray-100 pt-8">
        Stay Consistent &bull; Stay Soft &bull; Keep Learning
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
