export const getDaysDiff = (start: Date, end: Date): number => {
  const startDay = new Date(start.getFullYear(), start.getMonth(), start.getDate());
  const endDay = new Date(end.getFullYear(), end.getMonth(), end.getDate());
  const diffTime = endDay.getTime() - startDay.getTime();
  return Math.max(0, Math.floor(diffTime / (1000 * 60 * 60 * 24)));
};

export const calculateDebt = (
  startDateStr: string,
  labsCompleted: number,
  isExamMode: boolean,
  examModeStartDateStr: string | null,
  accumulatedExamDays: number
): number => {
  const now = new Date();
  const startDate = new Date(startDateStr);

  // Total calendar days elapsed since start (including day 0)
  const totalDaysPassed = getDaysDiff(startDate, now) + 1;

  // Calculate current session of exam mode if active
  let currentExamSessionDays = 0;
  if (isExamMode && examModeStartDateStr) {
    currentExamSessionDays = getDaysDiff(new Date(examModeStartDateStr), now);
  }

  const totalExamDays = accumulatedExamDays + currentExamSessionDays;

  // Effective days where a lab was expected
  const effectiveLearningDays = Math.max(0, totalDaysPassed - totalExamDays);

  // Debt = Target labs (1 per day) - Actual labs completed
  return Math.max(0, effectiveLearningDays - labsCompleted);
};

export const getLabsThisWeek = (labs: { completedAt: string }[]): number => {
  const now = new Date();
  const startOfWeek = new Date(now);
  // Set to last Sunday
  startOfWeek.setDate(now.getDate() - now.getDay());
  startOfWeek.setHours(0, 0, 0, 0);

  return labs.filter(lab => new Date(lab.completedAt) >= startOfWeek).length;
};

import React, { useState, useEffect } from 'react';
import { AppState, Lab, LabCategory } from './types';
import { calculateDebt, getLabsThisWeek, getDaysDiff } from './utils/dateUtils';
import { BentoCard } from './components/BentoCard';
import { ExamToggle } from './components/ExamToggle';
import { LabEntryForm } from './components/LabEntryForm';
import { WallOfProof } from './components/WallOfProof';

const STORAGE_KEY = 'cybersoft_tracker_v1';

const INITIAL_STATE: AppState = {
  journeyStartDate: new Date().toISOString(),
  labs: [],
  isExamMode: false,
  examModeStartDate: null,
  accumulatedExamDays: 0,
  weeklyGoal: 7,
};

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        console.error("Failed to parse storage", e);
      }
    }
    return INITIAL_STATE;
  });

  const [isEditingStart, setIsEditingStart] = useState(false);
  const [tempStartDate, setTempStartDate] = useState(state.journeyStartDate.split('T')[0]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const handleToggleExamMode = () => {
    setState(prev => {
      const now = new Date();
      if (!prev.isExamMode) {
        return {
          ...prev,
          isExamMode: true,
          examModeStartDate: now.toISOString(),
        };
      } else {
        const sessionDays = prev.examModeStartDate 
          ? getDaysDiff(new Date(prev.examModeStartDate), now) 
          : 0;
        return {
          ...prev,
          isExamMode: false,
          examModeStartDate: null,
          accumulatedExamDays: prev.accumulatedExamDays + sessionDays,
        };
      }
    });
  };

  const handleAddLab = (title: string, category: LabCategory, link: string) => {
    const newLab: Lab = {
      id: crypto.randomUUID(),
      title,
      category,
      resourceLink: link,
      completedAt: new Date().toISOString(),
    };
    setState(prev => ({
      ...prev,
      labs: [...prev.labs, newLab],
    }));
  };

  const handleDeleteLab = (id: string) => {
    if (window.confirm("Delete this proof of work?")) {
      setState(prev => ({
        ...prev,
        labs: prev.labs.filter(l => l.id !== id),
      }));
    }
  };

  const handleUpdateStartDate = () => {
    setState(prev => ({
      ...prev,
      journeyStartDate: new Date(tempStartDate).toISOString(),
      // Reset accumulated days if changing history significantly
      accumulatedExamDays: 0 
    }));
    setIsEditingStart(false);
  };

  const debt = calculateDebt(
    state.journeyStartDate,
    state.labs.length,
    state.isExamMode,
    state.examModeStartDate,
    state.accumulatedExamDays
  );

  const weeklyProgress = getLabsThisWeek(state.labs);
  const progressPercent = Math.min(100, (weeklyProgress / state.weeklyGoal) * 100);

  return (
    <div className="min-h-screen p-4 md:p-8 max-w-7xl mx-auto pb-24">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-6">
        <div className="space-y-1">
          <h1 className="text-5xl font-bold font-poppins text-gray-800 tracking-tight flex items-center gap-3">
            CyberSoft <span className="text-[#fbcfe8] animate-pulse">🌸</span>
          </h1>
          <p className="text-gray-500 font-medium text-lg">Cloud & Security Learning OS</p>
        </div>

        <div className="flex flex-col items-end bg-white/40 p-4 rounded-3xl border border-white/50 backdrop-blur-sm">
          <div className="text-[10px] font-mono text-gray-400 uppercase tracking-widest mb-1">Entry Timestamp</div>
          {isEditingStart ? (
            <div className="flex gap-2">
              <input 
                type="date" 
                value={tempStartDate} 
                onChange={(e) => setTempStartDate(e.target.value)}
                className="bg-white/80 border border-[#bfdbfe] rounded-xl px-3 py-1 text-sm outline-none focus:ring-2 focus:ring-[#bfdbfe]"
              />
              <button onClick={handleUpdateStartDate} className="bg-[#bfdbfe] px-4 py-1 rounded-xl text-xs font-bold text-gray-700 hover:bg-[#a5c9f9] transition-all">Update</button>
            </div>
          ) : (
            <button 
              onClick={() => setIsEditingStart(true)}
              className="group flex items-center gap-2 text-xl font-bold font-mono text-gray-700 hover:text-blue-500 transition-all"
            >
              {new Date(state.journeyStartDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
              <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 opacity-0 group-hover:opacity-100 transition-opacity" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
              </svg>
            </button>
          )}
