                  fill="none"
                  stroke="currentColor"
                  strokeWidth="12"
                  strokeDasharray={440}
                  strokeDashoffset={440 - (440 * state.syncPercentage) / 100}
                  strokeLinecap="round"
                  className={`${syncHealthColor} transition-all duration-1000 ease-out ${decayAmount > 0 ? 'opacity-50' : 'opacity-100'}`}
                />
              </svg>

              <div className={`absolute inset-0 flex flex-col items-center justify-center ${decayAmount > 0 ? 'animate-sync-glitch' : ''}`}>
                <span className="text-4xl font-black font-mono text-slate-800">{state.syncPercentage}%</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Synchronized</span>
              </div>
            </div>

            {state.syncPercentage < 40 && (
              <p className="mt-4 text-xs font-bold text-red-500 animate-pulse uppercase">Critical Sync Failure Imminent</p>
            )}
          </div>
        </BentoCard>

        {/* Card 2: Maintenance Mode */}
        <BentoCard 
          title="MAINTENANCE MODE" 
          icon={<Cpu className="w-5 h-5" />}
        >
          <div className="flex flex-col justify-between h-full gap-4">
            <p className="text-sm text-slate-500 leading-relaxed font-medium">
              Enable maintenance during exam weeks to pause the daily 10% sync decay protocol.
            </p>
            <button 
              onClick={() => setState(s => ({...s, maintenanceMode: !s.maintenanceMode}))}
              className={`flex items-center justify-between px-6 py-4 rounded-2xl border transition-all duration-300 ${
                state.maintenanceMode 
                ? 'bg-pink-500 text-white border-pink-600 shadow-lg shadow-pink-200' 
                : 'bg-white/50 text-slate-600 border-slate-200 hover:border-pink-300'
              }`}
            >
              <span className="font-bold text-sm uppercase tracking-widest">
                {state.maintenanceMode ? 'Active' : 'Standby'}
              </span>
              <div className={`w-10 h-6 rounded-full relative transition-colors ${state.maintenanceMode ? 'bg-white/30' : 'bg-slate-200'}`}>
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${state.maintenanceMode ? 'right-1' : 'left-1'}`} />
              </div>
            </button>
          </div>
        </BentoCard>

        {/* Card 3: Cloud Path Tracker */}
        <BentoCard 
          title="CLOUD SECURITY PATH" 
          icon={<Trophy className="w-5 h-5" />}
        >
          <div className="space-y-4">
            <div className="flex justify-between items-end">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Milestone: 100 Labs</span>
              <span className="text-xl font-black font-mono text-slate-800">{state.labs.length}/100</span>
            </div>
            <div className="w-full bg-slate-200/50 rounded-full h-4 overflow-hidden p-1">
              <div 
                className="h-full bg-gradient-to-r from-blue-400 to-pink-500 rounded-full transition-all duration-1000"
                style={{ width: `${pathProgress}%` }}
              />
            </div>
            <p className="text-[10px] text-center text-slate-400 font-medium italic">
              "The journey to cloud mastery is paved with validated proof-of-work."
            </p>
          </div>
        </BentoCard>

        {/* Card 4: Lab Entry Form */}
        <BentoCard 
          title="DECRYPT NEW LAB" 
          icon={<Terminal className="w-5 h-5" />}
          className="lg:col-span-1"
        >
          <form onSubmit={handleLogLab} className="space-y-4">
            <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Lab Name</label>
              <input 
                type="text" 
                value={labName}
                onChange={e => setLabName(e.target.value)}
                placeholder="AWS IAM Hardening"
                className="w-full bg-white/60 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Provider</label>
                <select 
                  value={provider}
                  onChange={e => setProvider(e.target.value as CloudProvider)}
                  className="w-full bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 appearance-none font-medium"
                >
                  {PROVIDERS.map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Github Link</label>
                <input 
                  type="url" 
                  value={githubLink}
                  onChange={e => setGithubLink(e.target.value)}
                  placeholder="https://github.com/..."
                  className="w-full bg-white/60 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
                />
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-slate-800 text-white font-bold py-3 rounded-xl hover:bg-slate-700 transition-all flex items-center justify-center gap-2 group shadow-lg shadow-slate-200"
            >
              COMMIT DEPLOYMENT 
              <Zap className="w-4 h-4 text-pink-400 group-hover:scale-125 transition-transform" />
            </button>
          </form>
        </BentoCard>

        {/* Card 5: Security Checklist */}
        <BentoCard 
          title="SECURITY CHECKLIST" 
          icon={<ListTodo className="w-5 h-5" />}
          className="lg:col-span-1"
        >
          <div className="flex flex-col h-full space-y-4">
            <form onSubmit={addChecklistItem} className="flex gap-2">
              <input 
                type="text" 
                value={newItemText}
                onChange={e => setNewItemText(e.target.value)}
                placeholder="New security task..."
                className="flex-1 bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
              />
              <button 
                type="submit"
                className="p-2 bg-pink-500 text-white rounded-xl hover:bg-pink-600 transition-all shadow-sm shadow-pink-100"
              >
                <Plus className="w-5 h-5" />
              </button>
            </form>

            <div className="overflow-y-auto max-h-[160px] space-y-2 pr-2 custom-scrollbar flex-1">
              {state.securityChecklist.length === 0 ? (
                <div className="text-center py-4">
                  <p className="text-[10px] text-slate-400 font-bold uppercase">No active protocols.</p>
                </div>
              ) : (
                state.securityChecklist.map(item => (
                  <div key={item.id} className="group flex items-center justify-between bg-white/40 p-2 rounded-xl border border-white/50 hover:bg-white/80 transition-all">
                    <button 
                      onClick={() => toggleChecklistItem(item.id)}
                      className="flex items-center gap-3 text-left flex-1"
                    >
                      {item.completed ? (
                        <CheckCircle2 className="w-5 h-5 text-pink-500 shrink-0" />
                      ) : (
                        <Circle className="w-5 h-5 text-slate-300 shrink-0" />
                      )}
                      <span className={`text-sm font-medium transition-all ${item.completed ? 'text-slate-400 line-through' : 'text-slate-700'}`}>
                        {item.text}
                      </span>
                    </button>
                    <button 
                      onClick={() => deleteChecklistItem(item.id)}
                      className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-400 transition-all"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </BentoCard>

        {/* Card 6: Deployment Log */}
        <BentoCard 
          title="DEPLOYMENT LOGS" 
          icon={<History className="w-5 h-5" />}
          className="lg:col-span-1 overflow-hidden flex flex-col"
        >
          <div className="overflow-y-auto max-h-[220px] space-y-3 pr-2 custom-scrollbar flex-1">
            {state.labs.length === 0 ? (
              <div className="text-center py-6">
                <p className="text-slate-400 font-mono text-[10px] uppercase">No validated data found.</p>
              </div>
            ) : (
              state.labs.map(lab => (
                <div key={lab.id} className="group bg-white/50 border border-slate-200/50 rounded-2xl p-3 flex items-center justify-between hover:bg-white hover:border-pink-200 transition-all">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-pink-100 flex items-center justify-center text-pink-500 font-bold text-[10px]">
                      {lab.provider.substring(0, 1)}
                    </div>
                    <div>
                      <h4 className="font-bold text-slate-800 text-[11px] leading-tight mb-0.5 truncate max-w-[120px]">{lab.name}</h4>
                      <div className="flex items-center gap-2 text-[9px] font-mono text-slate-400 uppercase tracking-tighter">
                        <span>{lab.provider}</span>
                        <span className="opacity-50">•</span>
                        <span>{new Date(lab.timestamp).toLocaleDateString()}</span>
                      </div>
                    </div>
                  </div>

                  <div className="flex items-center gap-1">
                    <a 
                      href={lab.githubLink} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="p-1.5 text-slate-400 hover:text-pink-500 hover:bg-pink-50 rounded-lg transition-all"
                    >
                      <Github className="w-3.5 h-3.5" />
                    </a>
                    <button 
                      onClick={() => deleteLab(lab.id)}
                      className="p-1.5 text-slate-300 hover:text-red-400 hover:bg-red-50 rounded-lg transition-all"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </BentoCard>

      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-slate-200 pt-8 flex flex-col md:flex-row justify-between items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest gap-4">
        <div className="flex items-center gap-2">
          <ShieldCheck className="w-3 h-3 text-pink-500" />
          AUTHENTICATED CLOUD SECURITY TRACKER
        </div>
        <div className="flex gap-8">
          <span className="hover:text-pink-500 transition-colors cursor-default">AWS</span>
          <span className="hover:text-blue-500 transition-colors cursor-default">AZURE</span>
          <span className="hover:text-slate-800 transition-colors cursor-default">GCP</span>
        </div>
        <div className="font-mono uppercase tracking-tighter">SYS_TIMESTAMP: {new Date().toISOString()}</div>
      </footer>
    </div>
  );
}

export type CloudProvider = 'AWS' | 'Azure' | 'GCP';

export interface Lab {
  id: string;
  name: string;
  provider: CloudProvider;
  githubLink: string;
  timestamp: string; // ISO string
}

export interface ChecklistItem {
  id: string;
  text: string;
  completed: boolean;
}

export interface Resource {
  id: string;
  title: string;
  type: 'Course' | 'Certification' | 'Doc' | 'Video';
  link: string;
  completed: boolean;
}

export interface AppState {
  syncPercentage: number;
  labs: Lab[];
  maintenanceMode: boolean;
  lastDecayTimestamp: string;
  streak: number;
  lastStreakUpdateDate: string | null; // Format: YYYY-MM-DD
  securityChecklist: ChecklistItem[];
  resourceVault: Resource[];
}

export const PROVIDERS: CloudProvider[] = ['AWS', 'Azure', 'GCP'];
export const RESOURCE_TYPES: Resource['type'][] = ['Course', 'Certification', 'Doc', 'Video'];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShieldCheck, 
  Activity, 
  Cpu, 
  Terminal, 
  Cloud, 
  Github, 
  Zap, 
  Trophy,
  History,
  Trash2,
  AlertTriangle,
  ListTodo,
  Plus,
  CheckCircle2,
  Circle,
  BookOpen,
  GraduationCap,
  Link as LinkIcon,
  PlayCircle,
  FileText
} from 'lucide-react';
import { AppState, Lab, CloudProvider, PROVIDERS, ChecklistItem, Resource, RESOURCE_TYPES } from './types';
import { applyDecay, updateStreak } from './utils/syncLogic';
import { BentoCard } from './components/BentoCard';

const STORAGE_KEY = 'cloudsec_mastery_state';

const INITIAL_STATE: AppState = {
  syncPercentage: 100,
  labs: [],
  maintenanceMode: false,
  lastDecayTimestamp: new Date().toISOString(),
  streak: 0,
  lastStreakUpdateDate: null,
  securityChecklist: [],
  resourceVault: []
};

export default function App() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migrations for new features
      if (!parsed.securityChecklist) parsed.securityChecklist = [];
      if (!parsed.resourceVault) parsed.resourceVault = [];
      return parsed;
    }
    return INITIAL_STATE;
  });

  const [labName, setLabName] = useState('');
  const [provider, setProvider] = useState<CloudProvider>('AWS');
  const [githubLink, setGithubLink] = useState('');
  const [decayAmount, setDecayAmount] = useState<number>(0);

  const [newItemText, setNewItemText] = useState('');

  // Resource Form State
  const [resTitle, setResTitle] = useState('');
  const [resType, setResType] = useState<Resource['type']>('Course');
  const [resLink, setResLink] = useState('');

  // Handle Daily Decay and Streak Check on Mount
  useEffect(() => {
    setState(prev => {
      const decayedState = applyDecay(prev);
      const diff = prev.syncPercentage - decayedState.syncPercentage;

      if (diff > 0) {
        setDecayAmount(diff);
        setTimeout(() => setDecayAmount(0), 4000);
      }

      return updateStreak(decayedState);
    });
  }, []);

  // Persist State
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const handleLogLab = (e: React.FormEvent) => {
    e.preventDefault();
    if (!labName || !githubLink) return;

    const newLab: Lab = {
      id: crypto.randomUUID(),
      name: labName,
      provider,
      githubLink,
      timestamp: new Date().toISOString()
    };

    setState(prev => ({
      ...prev,
      labs: [newLab, ...prev.labs],
      syncPercentage: Math.min(100, prev.syncPercentage + 25)
    }));

    setLabName('');
    setGithubLink('');
  };

  const deleteLab = (id: string) => {
    setState(prev => ({
      ...prev,
      labs: prev.labs.filter(l => l.id !== id)
    }));
  };

  const addChecklistItem = (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!newItemText.trim()) return;

    const newItem: ChecklistItem = {
      id: crypto.randomUUID(),
      text: newItemText.trim(),
      completed: false
    };

    setState(prev => ({
      ...prev,
      securityChecklist: [...prev.securityChecklist, newItem]
    }));
    setNewItemText('');
  };

  const toggleChecklistItem = (id: string) => {
    setState(prev => ({
      ...prev,
      securityChecklist: prev.securityChecklist.map(item => 
        item.id === id ? { ...item, completed: !item.completed } : item
      )
    }));
  };

  const deleteChecklistItem = (id: string) => {
    setState(prev => ({
      ...prev,
      securityChecklist: prev.securityChecklist.filter(item => item.id !== id)
    }));
  };

  // Resource Methods
  const addResource = (e: React.FormEvent) => {
    e.preventDefault();
    if (!resTitle.trim()) return;

    const newRes: Resource = {
      id: crypto.randomUUID(),
      title: resTitle.trim(),
      type: resType,
      link: resLink.trim(),
      completed: false
    };

    setState(prev => ({
      ...prev,
      resourceVault: [...prev.resourceVault, newRes]
    }));
    setResTitle('');
    setResLink('');
  };

  const toggleResource = (id: string) => {
    setState(prev => ({
      ...prev,
      resourceVault: prev.resourceVault.map(r => 
        r.id === id ? { ...r, completed: !r.completed } : r
      )
    }));
  };

  const deleteResource = (id: string) => {
    setState(prev => ({
      ...prev,
      resourceVault: prev.resourceVault.filter(r => r.id !== id)
    }));
  };

  const getResourceIcon = (type: Resource['type']) => {
    switch (type) {
      case 'Course': return <GraduationCap className="w-4 h-4" />;
      case 'Certification': return <ShieldCheck className="w-4 h-4" />;
      case 'Video': return <PlayCircle className="w-4 h-4" />;
      case 'Doc': return <FileText className="w-4 h-4" />;
      default: return <BookOpen className="w-4 h-4" />;
    }
  };

  const syncHealthColor = useMemo(() => {
    if (state.syncPercentage > 80) return 'text-pink-500';
    if (state.syncPercentage > 40) return 'text-blue-500';
    return 'text-red-400';
  }, [state.syncPercentage]);

  const pathProgress = Math.min(100, (state.labs.length / 100) * 100);

  return (
    <div className="min-h-screen px-4 py-10 md:px-12 lg:px-24">
      {/* Header */}
      <header className="mb-12 flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <div className="flex items-center gap-2 mb-2">
            <ShieldCheck className="text-pink-500 w-8 h-8" />
            <h1 className="text-4xl font-black font-poppins text-slate-800 tracking-tighter uppercase">CloudSec Master</h1>
          </div>
          <p className="text-slate-500 font-medium tracking-wide">DEPLOYING THE FUTURE OF CLOUD SECURITY</p>
        </div>

        <div className="flex items-center gap-6 bg-white/40 p-4 rounded-3xl border border-white/60 shadow-sm backdrop-blur-md">
          <div className="text-center px-4 border-r border-slate-200">
            <div className="text-[10px] font-mono text-slate-400 uppercase tracking-widest">Streak</div>
            <div className="text-2xl font-black text-pink-500 font-mono flex items-center gap-1 justify-center">
              <Zap className={`w-5 h-5 fill-current ${state.streak > 0 ? 'text-pink-500' : 'text-slate-300'}`} /> {state.streak}
            </div>
          </div>
          <div className="text-center px-4">
            <div className="text-[10px] font-mono text-slate-400 uppercase tracking-widest">Deployments</div>
            <div className="text-2xl font-black text-slate-800 font-mono">{state.labs.length}</div>
          </div>
        </div>
      </header>

      {/* Bento Grid */}
      <main className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">

        {/* Card 1: System Sync Status */}
        <BentoCard 
          title="SYSTEM SYNC HEALTH" 
          icon={<Activity className="w-5 h-5" />} 
          className="lg:row-span-1"
        >
          <div className="flex flex-col items-center justify-center h-full py-4 relative">
            {decayAmount > 0 && (
              <div className="absolute top-0 right-0 z-20 pointer-events-none">
                <div className="flex items-center gap-2 bg-red-50 text-red-600 px-3 py-1 rounded-full border border-red-100 shadow-sm animate-float-decay">
                  <AlertTriangle className="w-3 h-3" />
                  <span className="text-[10px] font-black font-mono">-{decayAmount}% SYNC DECAY</span>
                </div>
              </div>
            )}
            <div className="relative w-40 h-40">
              <svg className="w-full h-full transform -rotate-90">
                <circle cx="80" cy="80" r="70" fill="none" stroke="currentColor" strokeWidth="12" className="text-slate-200/50" />
                <circle cx="80" cy="80" r="70" fill="none" stroke="currentColor" strokeWidth="12" strokeDasharray={440} strokeDashoffset={440 - (440 * state.syncPercentage) / 100} strokeLinecap="round" className={`${syncHealthColor} transition-all duration-1000 ease-out ${decayAmount > 0 ? 'opacity-50' : 'opacity-100'}`} />
              </svg>
              <div className={`absolute inset-0 flex flex-col items-center justify-center ${decayAmount > 0 ? 'animate-sync-glitch' : ''}`}>
                <span className="text-4xl font-black font-mono text-slate-800">{state.syncPercentage}%</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Synchronized</span>
              </div>
            </div>
            {state.syncPercentage < 40 && (
              <p className="mt-4 text-xs font-bold text-red-500 animate-pulse uppercase">Critical Sync Failure Imminent</p>
            )}
          </div>
        </BentoCard>

        {/* Card 2: Maintenance Mode */}
        <BentoCard title="MAINTENANCE MODE" icon={<Cpu className="w-5 h-5" />}>
          <div className="flex flex-col justify-between h-full gap-4">
            <p className="text-sm text-slate-500 leading-relaxed font-medium">Pause the daily 10% sync decay protocol during exam weeks.</p>
            <button 
              onClick={() => setState(s => ({...s, maintenanceMode: !s.maintenanceMode}))}
              className={`flex items-center justify-between px-6 py-4 rounded-2xl border transition-all duration-300 ${state.maintenanceMode ? 'bg-pink-500 text-white border-pink-600 shadow-lg shadow-pink-200' : 'bg-white/50 text-slate-600 border-slate-200 hover:border-pink-300'}`}
            >
              <span className="font-bold text-sm uppercase tracking-widest">{state.maintenanceMode ? 'Active' : 'Standby'}</span>
              <div className={`w-10 h-6 rounded-full relative transition-colors ${state.maintenanceMode ? 'bg-white/30' : 'bg-slate-200'}`}>
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${state.maintenanceMode ? 'right-1' : 'left-1'}`} />
              </div>
            </button>
          </div>
        </BentoCard>

        {/* Card 3: Cloud Path Tracker */}
        <BentoCard title="CLOUD SECURITY PATH" icon={<Trophy className="w-5 h-5" />}>
          <div className="space-y-4">
            <div className="flex justify-between items-end">
              <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">Milestone: 100 Labs</span>
              <span className="text-xl font-black font-mono text-slate-800">{state.labs.length}/100</span>
            </div>
            <div className="w-full bg-slate-200/50 rounded-full h-4 overflow-hidden p-1">
              <div className="h-full bg-gradient-to-r from-blue-400 to-pink-500 rounded-full transition-all duration-1000" style={{ width: `${pathProgress}%` }} />
            </div>
          </div>
        </BentoCard>

        {/* Card 4: Resource Vault (The "Finished Course" Tracker) */}
        <BentoCard title="RESOURCE VAULT" icon={<BookOpen className="w-5 h-5" />} className="lg:col-span-1">
          <div className="flex flex-col h-full space-y-4">
            <form onSubmit={addResource} className="space-y-2">
              <input 
                type="text" value={resTitle} onChange={e => setResTitle(e.target.value)}
                placeholder="Course/Book Title..."
                className="w-full bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
              />
              <div className="flex gap-2">
                <select 
                  value={resType} onChange={e => setResType(e.target.value as any)}
                  className="bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-xs focus:outline-none font-bold text-slate-500 uppercase tracking-tighter"
                >
                  {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <input 
                  type="url" value={resLink} onChange={e => setResLink(e.target.value)}
                  placeholder="Link..."
                  className="flex-1 bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
                />
                <button type="submit" className="p-2 bg-pink-500 text-white rounded-xl hover:bg-pink-600 transition-all shadow-sm">
                  <Plus className="w-5 h-5" />
                </button>
              </div>
            </form>

            <div className="overflow-y-auto max-h-[160px] space-y-2 pr-2 custom-scrollbar flex-1">
              {state.resourceVault.length === 0 ? (
                <div className="text-center py-4"><p className="text-[10px] text-slate-400 font-bold uppercase">Vault Empty.</p></div>
              ) : (
                state.resourceVault.map(res => (
                  <div key={res.id} className="group flex items-center justify-between bg-white/40 p-2 rounded-xl border border-white/50 hover:bg-white/80 transition-all">
                    <button onClick={() => toggleResource(res.id)} className="flex items-center gap-3 text-left flex-1 min-w-0">
                      <div className={`shrink-0 ${res.completed ? 'text-pink-500' : 'text-slate-300'}`}>
                        {res.completed ? <CheckCircle2 className="w-5 h-5" /> : <Circle className="w-5 h-5" />}
                      </div>
                      <div className="min-w-0">
                        <div className="flex items-center gap-1.5">
                          <span className="text-pink-400 shrink-0">{getResourceIcon(res.type)}</span>
                          <span className={`text-sm font-bold truncate ${res.completed ? 'text-slate-400 line-through' : 'text-slate-800'}`}>
                            {res.title}
                          </span>
                        </div>
                        {res.link && (
                          <a href={res.link} target="_blank" rel="noopener noreferrer" className="text-[9px] text-blue-400 hover:underline flex items-center gap-1 mt-0.5">
                            <LinkIcon className="w-2 h-2" /> DATA_SOURCE
                          </a>
                        )}
                      </div>
                    </button>
                    <button onClick={() => deleteResource(res.id)} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-400 transition-all">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </BentoCard>

        {/* Card 5: Security Checklist */}
        <BentoCard title="SECURITY CHECKLIST" icon={<ListTodo className="w-5 h-5" />} className="lg:col-span-1">
          <div className="flex flex-col h-full space-y-4">
            <form onSubmit={addChecklistItem} className="flex gap-2">
              <input 
                type="text" value={newItemText} onChange={e => setNewItemText(e.target.value)}
                placeholder="New task..."
                className="flex-1 bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
              />
              <button type="submit" className="p-2 bg-pink-500 text-white rounded-xl hover:bg-pink-600 transition-all">
                <Plus className="w-5 h-5" />
              </button>
            </form>
            <div className="overflow-y-auto max-h-[160px] space-y-2 pr-2 custom-scrollbar flex-1">
              {state.securityChecklist.length === 0 ? (
                <div className="text-center py-4"><p className="text-[10px] text-slate-400 font-bold uppercase">No protocols.</p></div>
              ) : (
                state.securityChecklist.map(item => (
                  <div key={item.id} className="group flex items-center justify-between bg-white/40 p-2 rounded-xl border border-white/50 hover:bg-white/80 transition-all">
                    <button onClick={() => toggleChecklistItem(item.id)} className="flex items-center gap-3 text-left flex-1">
                      {item.completed ? <CheckCircle2 className="w-5 h-5 text-pink-500 shrink-0" /> : <Circle className="w-5 h-5 text-slate-300 shrink-0" />}
                      <span className={`text-sm font-medium transition-all ${item.completed ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{item.text}</span>
                    </button>
                    <button onClick={() => deleteChecklistItem(item.id)} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-400 transition-all">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>
        </BentoCard>

        {/* Card 6: Lab Entry Form */}
        <BentoCard title="DECRYPT NEW LAB" icon={<Terminal className="w-5 h-5" />} className="lg:col-span-1">
          <form onSubmit={handleLogLab} className="space-y-4">
            <input 
              type="text" value={labName} onChange={e => setLabName(e.target.value)} placeholder="AWS IAM Hardening"
              className="w-full bg-white/60 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
            />
            <div className="grid grid-cols-2 gap-4">
              <select 
                value={provider} onChange={e => setProvider(e.target.value as CloudProvider)}
                className="w-full bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 appearance-none font-medium"
              >
                {PROVIDERS.map(p => <option key={p} value={p}>{p}</option>)}
              </select>
              <input 
                type="url" value={githubLink} onChange={e => setGithubLink(e.target.value)} placeholder="https://github.com/..."
                className="w-full bg-white/60 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
              />
            </div>
            <button type="submit" className="w-full bg-slate-800 text-white font-bold py-3 rounded-xl hover:bg-slate-700 transition-all flex items-center justify-center gap-2 group shadow-lg">
              COMMIT DEPLOYMENT <Zap className="w-4 h-4 text-pink-400 group-hover:scale-125 transition-transform" />
            </button>
          </form>
        </BentoCard>

        {/* Card 7: Deployment Log */}
        <BentoCard title="DEPLOYMENT LOGS" icon={<History className="w-5 h-5" />} className="lg:col-span-3 overflow-hidden flex flex-col">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3 overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
            {state.labs.length === 0 ? (
              <div className="col-span-full text-center py-6"><p className="text-slate-400 font-mono text-[10px] uppercase">No registry data.</p></div>
            ) : (
              state.labs.map(lab => (
                <div key={lab.id} className="group bg-white/50 border border-slate-200/50 rounded-2xl p-3 flex items-center justify-between hover:bg-white hover:border-pink-200 transition-all">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-lg bg-pink-100 flex items-center justify-center text-pink-500 font-bold text-[10px] shrink-0">{lab.provider.substring(0, 1)}</div>
                    <div>
                      <h4 className="font-bold text-slate-800 text-[11px] leading-tight mb-0.5 truncate max-w-[120px]">{lab.name}</h4>
                      <div className="flex items-center gap-2 text-[9px] font-mono text-slate-400 uppercase tracking-tighter">
                        <span>{lab.provider}</span>
                        <span className="opacity-50">•</span>
                        <span>{new Date(lab.timestamp).toLocaleDateString()}</span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-1">
                    <a href={lab.githubLink} target="_blank" rel="noopener noreferrer" className="p-1.5 text-slate-400 hover:text-pink-500 hover:bg-pink-50 rounded-lg transition-all"><Github className="w-3.5 h-3.5" /></a>
                    <button onClick={() => deleteLab(lab.id)} className="p-1.5 text-slate-300 hover:text-red-400 hover:bg-red-50 rounded-lg transition-all"><Trash2 className="w-3.5 h-3.5" /></button>
                  </div>
                </div>
              ))
            )}
          </div>
        </BentoCard>

      </main>

      {/* Footer */}
      <footer className="mt-20 border-t border-slate-200 pt-8 flex flex-col md:flex-row justify-between items-center text-[10px] font-bold text-slate-400 uppercase tracking-widest gap-4">
        <div className="flex items-center gap-2"><ShieldCheck className="w-3 h-3 text-pink-500" /> AUTHENTICATED CLOUD SECURITY TRACKER</div>
        <div className="flex gap-8">
          <span className="hover:text-pink-500 transition-colors cursor-default">AWS</span>
          <span className="hover:text-blue-500 transition-colors cursor-default">AZURE</span>
          <span className="hover:text-slate-800 transition-colors cursor-default">GCP</span>
        </div>
        <div className="font-mono uppercase tracking-tighter">SYS_TIMESTAMP: {new Date().toISOString()}</div>
      </footer>
    </div>
  );
}

export type LabCategory = 'AWS' | 'Azure' | 'GCP' | 'Network' | 'AppSec' | 'Mandarin';

export interface Lab {
  id: string;
  name: string;
  category: LabCategory;
  githubLink: string;
  timestamp: string; // ISO string
}

export interface ChecklistItem {
  id: string;
  text: string;
  completed: boolean;
}

export interface Resource {
  id: string;
  title: string;
  type: 'Course' | 'Certification' | 'Doc' | 'Video';
  link: string;
  completed: boolean;
}

export interface AppState {
  syncPercentage: number;
  labs: Lab[];
  maintenanceMode: boolean;
  lastDecayTimestamp: string;
  journeyStartDate: string;
  streak: number;
  lastStreakUpdateDate: string | null;
  securityChecklist: ChecklistItem[];
  resourceVault: Resource[];
}

export const CATEGORIES: LabCategory[] = ['AWS', 'Azure', 'GCP', 'Network', 'AppSec', 'Mandarin'];
export const RESOURCE_TYPES: Resource['type'][] = ['Course', 'Certification', 'Doc', 'Video'];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShieldCheck, 
  Activity, 
  Cpu, 
  Terminal, 
  Cloud, 
  Github, 
  Zap, 
  Trophy,
  History,
  Trash2,
  AlertTriangle,
  ListTodo,
  Plus,
  CheckCircle2,
  Circle,
  BookOpen,
  GraduationCap,
  Link as LinkIcon,
  PlayCircle,
  FileText,
  Globe,
  Network,
  Lock,
  Calendar
} from 'lucide-react';
import { AppState, Lab, LabCategory, CATEGORIES, ChecklistItem, Resource, RESOURCE_TYPES } from './types';
import { applyDecay, updateStreak } from './utils/syncLogic';
import { BentoCard } from './components/BentoCard';

const STORAGE_KEY = 'cloudsec_mastery_state';

const INITIAL_STATE: AppState = {
  syncPercentage: 100,
  labs: [],
  maintenanceMode: false,
  lastDecayTimestamp: new Date().toISOString(),
  journeyStartDate: new Date().toISOString(),
  streak: 0,
  lastStreakUpdateDate: null,
  securityChecklist: [],
  resourceVault: []
};

export default function App() {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      const parsed = JSON.parse(saved);
      if (!parsed.securityChecklist) parsed.securityChecklist = [];
      if (!parsed.resourceVault) parsed.resourceVault = [];
      if (!parsed.journeyStartDate) parsed.journeyStartDate = new Date().toISOString();
      return parsed;
    }
    return INITIAL_STATE;
  });

  const [labName, setLabName] = useState('');
  const [category, setCategory] = useState<LabCategory>('AWS');
  const [githubLink, setGithubLink] = useState('');
  const [decayAmount, setDecayAmount] = useState<number>(0);

  const [newItemText, setNewItemText] = useState('');

  const [resTitle, setResTitle] = useState('');
  const [resType, setResType] = useState<Resource['type']>('Course');
  const [resLink, setResLink] = useState('');

  useEffect(() => {
    setState(prev => {
      const decayedState = applyDecay(prev);
      const diff = prev.syncPercentage - decayedState.syncPercentage;

      if (diff > 0) {
        setDecayAmount(diff);
        setTimeout(() => setDecayAmount(0), 4000);
      }

      return updateStreak(decayedState);
    });
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const handleLogLab = (e: React.FormEvent) => {
    e.preventDefault();
    if (!labName || !githubLink) return;

    const newLab: Lab = {
      id: crypto.randomUUID(),
      name: labName,
      category,
      githubLink,
      timestamp: new Date().toISOString()
    };

    setState(prev => ({
      ...prev,
      labs: [newLab, ...prev.labs],
      syncPercentage: Math.min(100, prev.syncPercentage + 25)
    }));

    setLabName('');
    setGithubLink('');
  };

  const addResource = (e: React.FormEvent) => {
    e.preventDefault();
    if (!resTitle.trim()) return;

    const newRes: Resource = {
      id: crypto.randomUUID(),
      title: resTitle.trim(),
      type: resType,
      link: resLink.trim(),
      completed: false
    };

    setState(prev => ({
      ...prev,
      resourceVault: [...prev.resourceVault, newRes]
    }));
    setResTitle('');
    setResLink('');
  };

  const toggleResource = (id: string) => {
    setState(prev => ({
      ...prev,
      resourceVault: prev.resourceVault.map(r => 
        r.id === id ? { ...r, completed: !r.completed } : r
      )
    }));
  };

  const deleteResource = (id: string) => {
    setState(prev => ({
      ...prev,
      resourceVault: prev.resourceVault.filter(r => r.id !== id)
    }));
  };

  const getResourceIcon = (type: Resource['type']) => {
    switch (type) {
      case 'Course': return <GraduationCap className="w-4 h-4" />;
      case 'Certification': return <ShieldCheck className="w-4 h-4" />;
      case 'Video': return <PlayCircle className="w-4 h-4" />;
      case 'Doc': return <FileText className="w-4 h-4" />;
      default: return <BookOpen className="w-4 h-4" />;
    }
  };

  const getCategoryIcon = (cat: LabCategory) => {
    switch(cat) {
      case 'AWS':
      case 'Azure':
      case 'GCP': return <Cloud className="w-3 h-3" />;
      case 'Network': return <Network className="w-3 h-3" />;
      case 'AppSec': return <Lock className="w-3 h-3" />;
      case 'Mandarin': return <Globe className="w-3 h-3" />;
      default: return <Terminal className="w-3 h-3" />;
    }
  };

  const resourceStats = useMemo(() => {
    const total = state.resourceVault.length;
    const completed = state.resourceVault.filter(r => r.completed).length;
    const progress = total === 0 ? 0 : Math.round((completed / total) * 100);
    return { total, completed, progress };
  }, [state.resourceVault]);

  const syncHealthColor = useMemo(() => {
    if (state.syncPercentage > 80) return 'text-pink-500';
    if (state.syncPercentage > 40) return 'text-blue-500';
    return 'text-red-400';
  }, [state.syncPercentage]);

  return (
    <div className="min-h-screen px-4 py-10 md:px-12 lg:px-24">
      {/* Header */}
      <header className="mb-12 flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <div className="flex items-center gap-2 mb-2">
            <ShieldCheck className="text-pink-500 w-8 h-8" />
            <h1 className="text-4xl font-black font-poppins text-slate-800 tracking-tighter uppercase">CloudSec Master</h1>
          </div>
          <p className="text-slate-500 font-medium tracking-wide">DEPLOYING THE FUTURE OF CLOUD SECURITY</p>
        </div>

        <div className="flex items-center gap-6 bg-white/40 p-4 rounded-3xl border border-white/60 shadow-sm backdrop-blur-md">
          <div className="text-center px-4 border-r border-slate-200">
            <div className="text-[10px] font-mono text-slate-400 uppercase tracking-widest">Streak</div>
            <div className="text-2xl font-black text-pink-500 font-mono flex items-center gap-1 justify-center">
              <Zap className={`w-5 h-5 fill-current ${state.streak > 0 ? 'text-pink-500' : 'text-slate-300'}`} /> {state.streak}
            </div>
          </div>
          <div className="text-center px-4 border-r border-slate-200">
            <div className="text-[10px] font-mono text-slate-400 uppercase tracking-widest">Vault Mastery</div>
            <div className="text-2xl font-black text-blue-500 font-mono">{resourceStats.progress}%</div>
          </div>
          <div className="text-center px-4">
            <div className="text-[10px] font-mono text-slate-400 uppercase tracking-widest">Deployments</div>
            <div className="text-2xl font-black text-slate-800 font-mono">{state.labs.length}</div>
          </div>
        </div>
      </header>

      {/* Bento Grid */}
      <main className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">

        {/* Card 1: System Sync Status */}
        <BentoCard title="SYSTEM SYNC HEALTH" icon={<Activity className="w-5 h-5" />} className="lg:row-span-1">
          <div className="flex flex-col items-center justify-center h-full py-4 relative">
            {decayAmount > 0 && (
              <div className="absolute top-0 right-0 z-20 pointer-events-none">
                <div className="flex items-center gap-2 bg-red-50 text-red-600 px-3 py-1 rounded-full border border-red-100 shadow-sm animate-float-decay">
                  <AlertTriangle className="w-3 h-3" />
                  <span className="text-[10px] font-black font-mono">-{decayAmount}% SYNC DECAY</span>
                </div>
              </div>
            )}
            <div className="relative w-40 h-40">
              <svg className="w-full h-full transform -rotate-90">
                <circle cx="80" cy="80" r="70" fill="none" stroke="currentColor" strokeWidth="12" className="text-slate-200/50" />
                <circle cx="80" cy="80" r="70" fill="none" stroke="currentColor" strokeWidth="12" strokeDasharray={440} strokeDashoffset={440 - (440 * state.syncPercentage) / 100} strokeLinecap="round" className={`${syncHealthColor} transition-all duration-1000 ease-out`} />
              </svg>
              <div className={`absolute inset-0 flex flex-col items-center justify-center ${decayAmount > 0 ? 'animate-sync-glitch' : ''}`}>
                <span className="text-4xl font-black font-mono text-slate-800">{state.syncPercentage}%</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Synchronized</span>
              </div>
            </div>
            <div className="mt-4 flex items-center gap-2 text-[10px] font-mono text-slate-400 uppercase">
              <Calendar className="w-3 h-3" /> Start: {new Date(state.journeyStartDate).toLocaleDateString()}
            </div>
          </div>
        </BentoCard>

        {/* Card 2: Resource Vault */}
        <BentoCard title="RESOURCE VAULT" icon={<BookOpen className="w-5 h-5" />} className="lg:col-span-1">
          <div className="flex flex-col h-full space-y-4">
            {/* Completion Summary */}
            <div className="space-y-1">
              <div className="flex justify-between items-end">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Protocol Completion</span>
                <span className="text-sm font-bold text-blue-500 font-mono">{resourceStats.completed}/{resourceStats.total}</span>
              </div>
              <div className="w-full bg-slate-100 rounded-full h-1.5 overflow-hidden">
                <div className="h-full bg-blue-400 transition-all duration-700" style={{ width: `${resourceStats.progress}%` }} />
              </div>
            </div>

            <form onSubmit={addResource} className="space-y-2">
              <input 
                type="text" value={resTitle} onChange={e => setResTitle(e.target.value)}
                placeholder="Resource Title..."
                className="w-full bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-blue-400 transition-all font-medium"
              />
              <div className="flex gap-2">
                <select 
                  value={resType} onChange={e => setResType(e.target.value as any)}
                  className="bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-[10px] focus:outline-none font-black text-slate-500 uppercase"
                >
                  {RESOURCE_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <input 
                  type="url" value={resLink} onChange={e => setResLink(e.target.value)}
                  placeholder="URL..."
                  className="flex-1 bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-blue-400 transition-all font-medium"
                />
                <button type="submit" className="p-2 bg-blue-500 text-white rounded-xl hover:bg-blue-600 transition-all">
                  <Plus className="w-5 h-5" />
                </button>
              </div>
            </form>

            <div className="overflow-y-auto max-h-[160px] space-y-2 pr-2 custom-scrollbar flex-1">
              {state.resourceVault.map(res => (
                <div key={res.id} className={`group flex items-center justify-between p-2 rounded-xl border transition-all ${res.completed ? 'bg-blue-50/50 border-blue-100' : 'bg-white/40 border-white/50 hover:bg-white/80'}`}>
                  <button onClick={() => toggleResource(res.id)} className="flex items-center gap-3 text-left flex-1 min-w-0">
                    <div className={`shrink-0 ${res.completed ? 'text-blue-500' : 'text-slate-300'}`}>
                      {res.completed ? <CheckCircle2 className="w-5 h-5" /> : <Circle className="w-5 h-5" />}
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-1.5">
                        <span className={`${res.completed ? 'text-blue-400' : 'text-slate-400'} shrink-0`}>{getResourceIcon(res.type)}</span>
                        <span className={`text-sm font-bold truncate ${res.completed ? 'text-slate-400 line-through' : 'text-slate-800'}`}>{res.title}</span>
                      </div>
                    </div>
                  </button>
                  <div className="flex items-center gap-1">
                    {res.link && (
                      <a href={res.link} target="_blank" rel="noopener noreferrer" className="p-1.5 text-blue-400 hover:bg-blue-100 rounded-lg"><LinkIcon className="w-3.5 h-3.5" /></a>
                    )}
                    <button onClick={() => deleteResource(res.id)} className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-300 hover:text-red-400 transition-all"><Trash2 className="w-3.5 h-3.5" /></button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </BentoCard>

        {/* Card 3: Security Checklist */}
        <BentoCard title="SECURITY CHECKLIST" icon={<ListTodo className="w-5 h-5" />} className="lg:col-span-1">
          <div className="flex flex-col h-full space-y-4">
            <form onSubmit={(e) => { e.preventDefault(); if(newItemText) { setState(s => ({...s, securityChecklist: [...s.securityChecklist, {id: crypto.randomUUID(), text: newItemText, completed: false}]})); setNewItemText(''); } }} className="flex gap-2">
              <input type="text" value={newItemText} onChange={e => setNewItemText(e.target.value)} placeholder="New task..." className="flex-1 bg-white/60 border border-slate-200 rounded-xl px-3 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium" />
              <button type="submit" className="p-2 bg-pink-500 text-white rounded-xl hover:bg-pink-600 transition-all"><Plus className="w-5 h-5" /></button>
            </form>
            <div className="overflow-y-auto max-h-[160px] space-y-2 pr-2 custom-scrollbar flex-1">
              {state.securityChecklist.map(item => (
                <div key={item.id} className="group flex items-center justify-between bg-white/40 p-2 rounded-xl border border-white/50 hover:bg-white/80 transition-all">
                  <button onClick={() => setState(s => ({...s, securityChecklist: s.securityChecklist.map(i => i.id === item.id ? {...i, completed: !i.completed} : i)}))} className="flex items-center gap-3 text-left flex-1">
                    {item.completed ? <CheckCircle2 className="w-5 h-5 text-pink-500 shrink-0" /> : <Circle className="w-5 h-5 text-slate-300 shrink-0" />}
                    <span className={`text-sm font-medium transition-all ${item.completed ? 'text-slate-400 line-through' : 'text-slate-700'}`}>{item.text}</span>
                  </button>
                  <button onClick={() => setState(s => ({...s, securityChecklist: s.securityChecklist.filter(i => i.id !== item.id)}))} className="opacity-0 group-hover:opacity-100 p-1 text-slate-300 hover:text-red-400 transition-all"><Trash2 className="w-4 h-4" /></button>
                </div>
              ))}
            </div>
          </div>
        </BentoCard>

        {/* Card 4: Lab Entry Form */}
        <BentoCard title="DECRYPT NEW LAB" icon={<Terminal className="w-5 h-5" />} className="lg:col-span-1">
          <form onSubmit={handleLogLab} className="space-y-4">
            <input 
              type="text" value={labName} onChange={e => setLabName(e.target.value)} placeholder="Lab Title..."
              className="w-full bg-white/60 border border-slate-200 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-pink-400 transition-all font-medium"
            />
